def minPath(grid, k):
    n = len(grid)
    r = c = 0
    for i in range(n):
        for j in range(n):
            if grid[i][j] == 1:
                r, c = i, j
    neighbors = []
    for dr, dc in [(-1, 0), (1, 0), (0, -1), (0, 1)]:
        nr, nc = r + dr, c + dc
        if 0 <= nr < n and 0 <= nc < n:
            neighbors.append(grid[nr][nc])
    m = min(neighbors)
    return [1 if i % 2 == 0 else m for i in range(k)]

